const now = new Date();
const hour = now.getHours();
const isBusinessHours = hour >= 8 && hour <= 21;

const staticData = $getWorkflowStaticData('global');
const today = now.toISOString().split('T')[0];
if (staticData.lastDate !== today) {
  staticData.lastDate = today;
  staticData.sentToday = 0;
}

const maxPerDay = 30;
const canSend = isBusinessHours && staticData.sentToday < maxPerDay;

return [{
  json: {
    canSend,
    sentToday: staticData.sentToday,
    maxPerDay,
    currentHour: hour
  }
}];

