const staticData = $getWorkflowStaticData('global');
if (!staticData.usedSubjects) staticData.usedSubjects = [];

let available = conversations.filter(c => !staticData.usedSubjects.includes(c.subject));
if (available.length === 0) {
  staticData.usedSubjects = [];
  available = conversations;
}

const picked = available[Math.floor(Math.random() * available.length)];
staticData.usedSubjects.push(picked.subject);
if (staticData.usedSubjects.length > 12) {
  staticData.usedSubjects = staticData.usedSubjects.slice(-12);
}

return [{
  json: {
    ...$input.first().json,
    subject: picked.subject,
    body: picked.body
  }
}];

