const useShort = Math.random() < 0.6;
const pool = useShort ? shortReplies : mediumReplies;
const reply = pool[Math.floor(Math.random() * pool.length)];

const origSubject = $input.first().json.subject || 'your message';
const replySubject = origSubject.startsWith('Re:') ? origSubject : 'Re: ' + origSubject;

const fromField = $input.first().json.from || '';
const match = fromField.match(/<(.+?)>/);
const senderEmail = match ? match[1] : fromField.trim();

return [{
  json: {
    replyTo: senderEmail,
    subject: replySubject,
    body: reply
  }
}];

return [{
  json: {
    status: 'REPLY_SENT',
    repliedTo: $input.first().json.replyTo,
    subject: $input.first().json.subject,
    timestamp: new Date().toISOString()
  }
}];

