// SPAM RESCUE
// =============================================
// This node detects bygweb.com emails in spam.
//
// TO ACTUALLY MOVE THE EMAIL:
// Add a Gmail/Outlook API node after this:
//
// Gmail: Use Gmail node → Modify Labels
//   - Remove: SPAM
//   - Add: INBOX, IMPORTANT
//
// Outlook: Use Microsoft Graph → Move Message
//   - Destination: inbox
//
// The detection + logging alone helps track
// spam rate. The API node does the actual rescue.

const email = $input.first().json;

const staticData = $getWorkflowStaticData('global');
if (!staticData.rescueCount) staticData.rescueCount = 0;
staticData.rescueCount++;

return [{
  json: {
    action: 'RESCUED_FROM_SPAM',
    from: email.from,
    subject: email.subject || '(no subject)',
    messageId: email.messageId || '',
    totalRescues: staticData.rescueCount,
    rescuedAt: new Date().toISOString(),
    warning: staticData.rescueCount > 10 
      ? 'HIGH SPAM RATE! Check SPF/DKIM/DMARC records for bygweb.com'
      : 'Normal'
  }
}];

return [{
  json: {
    status: 'SPAM_RESCUED',
    from: $input.first().json.from,
    subject: $input.first().json.subject,
    totalRescues: $input.first().json.totalRescues,
    timestamp: new Date().toISOString()
  }
}];
